"use client";

import Card from "@/components/ui/Card";
import Avatar from "@/components/ui/Avatar";
import Badge from "@/components/ui/Badge";
import { conversations, currentUser } from "@/lib/data";
import { formatRelativeTime } from "@/lib/utils";
import { MessageSquare } from "lucide-react";
import Link from "next/link";

export default function RecentMessages() {
  const recentConversations = conversations.slice(0, 3);

  return (
    <Card>
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-semibold text-gray-900">Messages</h3>
        <Link
          href="/chat"
          className="text-sm text-emerald-600 hover:text-emerald-700 font-medium"
        >
          View all
        </Link>
      </div>
      <div className="space-y-3">
        {recentConversations.map((conv) => {
          const other = conv.participants.find(
            (p) => p.id !== currentUser.id
          ) || conv.participants[1];

          return (
            <Link
              key={conv.id}
              href="/chat"
              className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 border border-gray-100 hover:border-emerald-200 transition-colors"
            >
              <div className="relative">
                <Avatar src={other.avatar} alt={other.name} size="md" />
                {conv.unreadCount > 0 && (
                  <span className="absolute -top-0.5 -right-0.5 w-4 h-4 bg-emerald-500 text-white text-[9px] font-bold rounded-full flex items-center justify-center">
                    {conv.unreadCount}
                  </span>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center justify-between mb-0.5">
                  <p className="font-medium text-gray-900 truncate text-sm">
                    {other.name}
                  </p>
                  <span className="text-xs text-gray-400 shrink-0 ml-2">
                    {formatRelativeTime(conv.lastMessageTime)}
                  </span>
                </div>
                <div className="flex items-center gap-1.5 mb-1">
                  <Badge variant="success" size="sm">
                    {conv.skillExchange.skill1}
                  </Badge>
                  <span className="text-gray-400 text-xs">↔</span>
                  <Badge variant="info" size="sm">
                    {conv.skillExchange.skill2}
                  </Badge>
                </div>
                <p className="text-xs text-gray-500 truncate">
                  {conv.lastMessage}
                </p>
              </div>
            </Link>
          );
        })}
      </div>
    </Card>
  );
}
